public class XHyperlinkWfdForRelatedStateWidget extends XAbstractHyperlinkWithFilteredDialogWidget<String> {   public static final WidgetId ID = WidgetIdAts.XHyperlinkWfdForRelatedStateWidget;   private final Collection<String> selectable;   public XHyperlinkWfdForRelatedStateWidget() {      this(Collections.emptyList());   }   public XHyperlinkWfdForRelatedStateWidget(Collection<String> selectable) {      this(ID, selectable);   }   public XHyperlinkWfdForRelatedStateWidget(WidgetId widgetId, Collection<String> selectable) {      super(widgetId, "Related State");      this.selectable = selectable;      setToolTip(RelatedToStateColumnUI.RELATED_TO_STATE_SELECTION);   }   @Override   public Collection<String> getSelectable() {      if (selectable != null) {         return selectable;      } else {         return Collections.emptyList();      }   }}